// Resource class (equivalent to Spring controller)
@Path(\"/api/users\")
@Produces(MediaType.APPLICATION_JSON)
@Consumes(MediaType.APPLICATION_JSON)
class UserResource {
    // Create new user
    @POST
    public Response createUser(@Valid User user) {
        // Check for duplicate username
        User.findByUsername(user.username).ifPresent(u -> {
            throw new WebApplicationException(\"Username already exists\", Response.Status.CONFLICT);
        });
        // Check for duplicate email
        User.findByEmail(user.email).ifPresent(u -> {
            throw new WebApplicationException(\"Email already exists\", Response.Status.CONFLICT);
        });
        user.persist();
        return Response.status(Response.Status.CREATED).entity(user).build();
    }

    // Get all users
    @GET
    public List getAllUsers() {
        return User.listAll();
    }

    // Get user by id
    @GET
    @Path(\"/{id}\")
    public User getUserById(@PathParam(\"id\") Long id) {
        return User.findByIdOptional(id)
                .orElseThrow(() -> new WebApplicationException(\"User not found with id: \" + id, Response.Status.NOT_FOUND));
    }

    // Update user
    @PUT
    @Path(\"/{id}\")
    public User updateUser(@PathParam(\"id\") Long id, @Valid User userDetails) {
        User existingUser = User.findByIdOptional(id)
                .orElseThrow(() -> new WebApplicationException(\"User not found with id: \" + id, Response.Status.NOT_FOUND));
        // Check if new username is taken by another user
        User.findByUsername(userDetails.username).ifPresent(u -> {
            if (!u.id.equals(id)) {
                throw new WebApplicationException(\"Username already exists\", Response.Status.CONFLICT);
            }
        });
        // Check if new email is taken by another user
        User.findByEmail(userDetails.email).ifPresent(u -> {
            if (!u.id.equals(id)) {
                throw new WebApplicationException(\"Email already exists\", Response.Status.CONFLICT);
            }
        });
        existingUser.username = userDetails.username;
        existingUser.email = userDetails.email;
        existingUser.fullName = userDetails.fullName;
        existingUser.persist();
        return existingUser;
    }

    // Delete user
    @DELETE
    @Path(\"/{id}\")
    public Response deleteUser(@PathParam(\"id\") Long id) {
        User existingUser = User.findByIdOptional(id)
                .orElseThrow(() -> new WebApplicationException(\"User not found with id: \" + id, Response.Status.NOT_FOUND));
        existingUser.delete();
        return Response.status(Response.Status.NO_CONTENT).build();
    }
}

